import{_ as e,o as t,c as a,Q as i}from"./chunks/framework.b67c47e6.js";const o="/assets/viewer_layout.13209dd2.png",s="/assets/viewer_3d.442d248e.png",r="/assets/viewer_clipping.4717c830.png",n="/assets/viewer_drawings.2bfc6783.png",l="/assets/viewer_bom.e29b7760.png",c="/assets/viewer_checklist.8105dd7c.png",h="/assets/viewer_issues.26f028e8.png",v=JSON.parse('{"title":"3D Viewer","description":"","frontmatter":{},"headers":[],"relativePath":"guide/viewer/index.md","filePath":"guide/viewer/index.md","lastUpdated":1774023996000}'),d={name:"guide/viewer/index.md"},u=i('<h1 id="_3d-viewer" tabindex="-1">3D Viewer <a class="header-anchor" href="#_3d-viewer" aria-label="Permalink to &quot;3D Viewer&quot;">​</a></h1><p>The Viewer is the main production interface in produuz.it. It displays 3D models and technical drawings of your constructibles (assemblies and modules), and provides tools for managing production checklists, issues, logistics, and more.</p><nav class="table-of-contents"><ul><li><a href="#accessing-the-viewer">Accessing the Viewer</a></li><li><a href="#layout">Layout</a></li><li><a href="#_3d-model">3D Model</a><ul><li><a href="#controls">Controls</a></li><li><a href="#selecting-parts">Selecting Parts</a></li><li><a href="#zone-selection">Zone Selection</a></li><li><a href="#advanced-tools">Advanced Tools</a></li></ul></li><li><a href="#technical-drawings">Technical Drawings</a></li><li><a href="#bill-of-materials-bom">Bill of Materials (BOM)</a><ul><li><a href="#part-list">Part List</a></li><li><a href="#unknown-parts">Unknown Parts</a></li><li><a href="#part-drawings">Part Drawings</a></li></ul></li><li><a href="#production-features">Production Features</a><ul><li><a href="#checklist">Checklist</a></li><li><a href="#station-switching">Station Switching</a></li><li><a href="#issues">Issues</a></li><li><a href="#qr-code">QR Code</a></li><li><a href="#rfid-tag">RFID Tag</a></li><li><a href="#rack-logistics">Rack / Logistics</a></li></ul></li><li><a href="#specifications-documents">Specifications &amp; Documents</a></li></ul></nav><h2 id="accessing-the-viewer" tabindex="-1">Accessing the Viewer <a class="header-anchor" href="#accessing-the-viewer" aria-label="Permalink to &quot;Accessing the Viewer&quot;">​</a></h2><p>You can open the Viewer from the constructibles list in a project. There are two viewing modes:</p><ul><li><strong>Actual Viewer</strong> — For constructibles in production. Includes checklists, issues, RFID, and logistics features.</li><li><strong>Design Viewer</strong> — For reviewing designs before production. Shows 3D models and drawings in read-only mode (no production tools).</li></ul><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p><img src="'+o+'" alt="Viewer Layout"></p><p>The Viewer uses a three-panel layout:</p><table><thead><tr><th>Panel</th><th>Content</th></tr></thead><tbody><tr><td><strong>Left</strong></td><td>3D model or technical drawing (PDF)</td></tr><tr><td><strong>Center</strong></td><td>Vertical toolbar with action buttons</td></tr><tr><td><strong>Right</strong></td><td>Part details (BOM) or specification documents</td></tr></tbody></table><p>You can switch between three view modes using the buttons in the top-right corner:</p><ul><li><strong>Drawing mode</strong> — Left panel + toolbar only (focus on 3D/drawings).</li><li><strong>Full mode</strong> — All three panels visible.</li><li><strong>Detail mode</strong> — Toolbar + right panel only (focus on part details).</li></ul><h2 id="_3d-model" tabindex="-1">3D Model <a class="header-anchor" href="#_3d-model" aria-label="Permalink to &quot;3D Model&quot;">​</a></h2><p><img src="'+s+'" alt="3D Model"></p><h3 id="controls" tabindex="-1">Controls <a class="header-anchor" href="#controls" aria-label="Permalink to &quot;Controls&quot;">​</a></h3><ul><li><strong>Rotate</strong> — Click and drag to rotate the model.</li><li><strong>Zoom</strong> — Scroll wheel or double-click to zoom in.</li><li><strong>Pan</strong> — Right-click and drag to move around.</li><li><strong>Recenter</strong> — Click the crosshair button to reset the view.</li><li><strong>Front/Back</strong> — Toggle buttons to flip the camera perspective.</li></ul><h3 id="selecting-parts" tabindex="-1">Selecting Parts <a class="header-anchor" href="#selecting-parts" aria-label="Permalink to &quot;Selecting Parts&quot;">​</a></h3><p>Click any part in the 3D model to select it. The right panel will show its properties, including:</p><ul><li>Zone and reference number</li><li>Material type and dimensions</li><li>IFC properties and property sets</li><li>Creation date and revision number</li></ul><h3 id="zone-selection" tabindex="-1">Zone Selection <a class="header-anchor" href="#zone-selection" aria-label="Permalink to &quot;Zone Selection&quot;">​</a></h3><p>Use the zone toggle buttons to show or hide specific zones of the constructible. This is useful for focusing on a specific area during production.</p><p>For modules, you can also filter by sub-assembly using the assembly dropdown.</p><h3 id="advanced-tools" tabindex="-1">Advanced Tools <a class="header-anchor" href="#advanced-tools" aria-label="Permalink to &quot;Advanced Tools&quot;">​</a></h3><ul><li><strong>Measurement</strong> — Click the ruler icon to measure distances between parts in the 3D view.</li><li><strong>Clipping Plane</strong> — Click the section icon to enable a cutting plane that reveals the interior structure.</li></ul><p><img src="'+r+'" alt="Clipping Plane"></p><h2 id="technical-drawings" tabindex="-1">Technical Drawings <a class="header-anchor" href="#technical-drawings" aria-label="Permalink to &quot;Technical Drawings&quot;">​</a></h2><p><img src="'+n+'" alt="Technical Drawings"></p><p>The left panel can switch between the 3D model and technical drawings (PDFs). Use the buttons at the bottom of the left panel to select which drawing to display.</p><ul><li>Drawings are filtered by your selected production station when applicable.</li><li>Multi-page drawings show navigation arrows to move between pages.</li><li>Zoom and pan controls work the same as in the 3D view.</li></ul><h2 id="bill-of-materials-bom" tabindex="-1">Bill of Materials (BOM) <a class="header-anchor" href="#bill-of-materials-bom" aria-label="Permalink to &quot;Bill of Materials (BOM)&quot;">​</a></h2><p><img src="'+l+'" alt="Bill of Materials"></p><p>The right panel in <strong>Details</strong> mode shows the Bill of Materials for the current constructible.</p><h3 id="part-list" tabindex="-1">Part List <a class="header-anchor" href="#part-list" aria-label="Permalink to &quot;Part List&quot;">​</a></h3><p>A table listing all tracked parts with:</p><ul><li>Reference number</li><li>Part category badge</li><li>Specifications</li><li>Zone location</li></ul><p>Use the <strong>branch filter</strong> buttons (e.g., wood, metal, hardware) to show only parts from a specific construction branch.</p><h3 id="unknown-parts" tabindex="-1">Unknown Parts <a class="header-anchor" href="#unknown-parts" aria-label="Permalink to &quot;Unknown Parts&quot;">​</a></h3><p>A separate tab shows parts detected in the IFC file but not matched to the database. This helps identify parts that may need to be added to the system.</p><h3 id="part-drawings" tabindex="-1">Part Drawings <a class="header-anchor" href="#part-drawings" aria-label="Permalink to &quot;Part Drawings&quot;">​</a></h3><p>When a part is selected, you can view its associated detail drawings and CAD files in the right panel.</p><h2 id="production-features" tabindex="-1">Production Features <a class="header-anchor" href="#production-features" aria-label="Permalink to &quot;Production Features&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Production features are only available in the <strong>Actual Viewer</strong> (not in Design Viewer).</p></div><h3 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h3><p><img src="'+c+'" alt="Checklist Dialog"></p><p>The checklist button in the toolbar shows the production progress for the current constructible at the selected station.</p><ul><li><strong>Progress bar</strong> — Color-coded: red (not started), amber (in progress), green (completed).</li><li><strong>Task list</strong> — Each task has a checkbox, and may require: <ul><li>QR code scanning</li><li>Picture upload (opens camera interface)</li><li>Filling a custom form</li><li>Reviewing associated documents</li></ul></li></ul><p><strong>Actions:</strong></p><ul><li><strong>Start Production</strong> — Begin work on this station (required before checking tasks).</li><li><strong>Pause</strong> — Temporarily stop work.</li><li><strong>Station Job Completed</strong> — Mark the station as done (enabled when all tasks are checked).</li></ul><h3 id="station-switching" tabindex="-1">Station Switching <a class="header-anchor" href="#station-switching" aria-label="Permalink to &quot;Station Switching&quot;">​</a></h3><p>Click the station button to change to a different production station. If previous stations haven&#39;t been completed, you&#39;ll be asked to confirm a force-start.</p><h3 id="issues" tabindex="-1">Issues <a class="header-anchor" href="#issues" aria-label="Permalink to &quot;Issues&quot;">​</a></h3><p><img src="'+h+'" alt="Issues Dialog"></p><p>The issues button shows a badge with the count of active issues for this constructible.</p><ul><li><strong>View issues</strong> — See all issues with their title, description, category, status, and attached pictures.</li><li><strong>Add issue</strong> — Create a new issue with a category, title, description, and optional picture upload. You can attach the current part information for context.</li></ul><h3 id="qr-code" tabindex="-1">QR Code <a class="header-anchor" href="#qr-code" aria-label="Permalink to &quot;QR Code&quot;">​</a></h3><p>Click the QR button to display a QR code for the current constructible. This can be printed and attached to the physical item for quick identification on the shop floor.</p><h3 id="rfid-tag" tabindex="-1">RFID Tag <a class="header-anchor" href="#rfid-tag" aria-label="Permalink to &quot;RFID Tag&quot;">​</a></h3><p>Click the RFID button to register an RFID tag code for the current constructible. You can type the code manually or scan it using the camera.</p><h3 id="rack-logistics" tabindex="-1">Rack / Logistics <a class="header-anchor" href="#rack-logistics" aria-label="Permalink to &quot;Rack / Logistics&quot;">​</a></h3><p>The rack button shows whether the constructible has been loaded into a delivery rack.</p><ul><li><strong>Load to Rack</strong> — Mark the item as placed in a rack.</li><li><strong>Unload from Rack</strong> — Remove the rack assignment.</li><li>Shows a visual representation of the rack arrangement.</li></ul><h2 id="specifications-documents" tabindex="-1">Specifications &amp; Documents <a class="header-anchor" href="#specifications-documents" aria-label="Permalink to &quot;Specifications &amp; Documents&quot;">​</a></h2><p>Switch to the <strong>Docs</strong> mode in the right panel to view specification documents associated with the constructible. These may include finish specifications, hardware specs, or other technical documents in PDF or image format.</p>',63),p=[u];function g(m,f,b,w,k,P){return t(),a("div",null,p)}const q=e(d,[["render",g]]);export{v as __pageData,q as default};
